// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.

public enum TrzszPublicState: Equatable, Hashable {
    
    case idle
    case waitingUser(transferId: String, mode: String, suggestedName: String?, expectedSize: UInt64?
    )
    case inProgress(transferId: String, mode: String, fileName: String?, transferred: UInt64, total: UInt64?
    )
    case done(transferId: String, success: Bool, message: String?
    )





}

#if compiler(>=6)
extension TrzszPublicState: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeTrzszPublicState: FfiConverterRustBuffer {
    typealias SwiftType = TrzszPublicState

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> TrzszPublicState {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .idle
        
        case 2: return .waitingUser(transferId: try FfiConverterString.read(from: &buf), mode: try FfiConverterString.read(from: &buf), suggestedName: try FfiConverterOptionString.read(from: &buf), expectedSize: try FfiConverterOptionUInt64.read(from: &buf)
        )
        
        case 3: return .inProgress(transferId: try FfiConverterString.read(from: &buf), mode: try FfiConverterString.read(from: &buf), fileName: try FfiConverterOptionString.read(from: &buf), transferred: try FfiConverterUInt64.read(from: &buf), total: try FfiConverterOptionUInt64.read(from: &buf)
        )
        
        case 4: return .done(transferId: try FfiConverterString.read(from: &buf), success: try FfiConverterBool.read(from: &buf), message: try FfiConverterOptionString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: TrzszPublicState, into buf: inout [UInt8]) {
        switch value {
        
        
        case .idle:
            writeInt(&buf, Int32(1))
        
        
        case let .waitingUser(transferId,mode,suggestedName,expectedSize):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(transferId, into: &buf)
            FfiConverterString.write(mode, into: &buf)
            FfiConverterOptionString.write(suggestedName, into: &buf)
            FfiConverterOptionUInt64.write(expectedSize, into: &buf)
            
        
        case let .inProgress(transferId,mode,fileName,transferred,total):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(transferId, into: &buf)
            FfiConverterString.write(mode, into: &buf)
            FfiConverterOptionString.write(fileName, into: &buf)
            FfiConverterUInt64.write(transferred, into: &buf)
            FfiConverterOptionUInt64.write(total, into: &buf)
            
        
        case let .done(transferId,success,message):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(transferId, into: &buf)
            FfiConverterBool.write(success, into: &buf)
            FfiConverterOptionString.write(message, into: &buf)
            
        }
    }
}


